    model_config = DEFAULT_PYDANTIC_MODEL_CONFIG

    @property
    def offset(self) -&gt; int:
        return max(0, self.page_at - self.page_base) * self.page_size

    @property
    def limit(self) -&gt; int:
        return self.page_size
